import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";


const SHAPES = [
  { key: "slab", label: "Slab / Footing" },
  { key: "column", label: "Column / Cylinder" },
  { key: "stairs", label: "Stairs" },
];

const FAQS = [
  { q: "How do I calculate how much concrete I need?", a: "For a slab: Volume (cu yd) = (Length  x  Width  x  Thickness in feet) / 27. For a column: Volume = pi  x  radius-  x  height / 27. Always add 10% extra for waste." },
  { q: "How many bags of concrete per cubic yard?", a: "A 60-lb bag yields approximately 0.45 cu ft. A 80-lb bag yields about 0.60 cu ft. One cubic yard = 27 cu ft, so you'd need about 45 80-lb bags per cubic yard, or 60 60-lb bags." },
  { q: "How much does a cubic yard of concrete weigh?", a: "Ready-mix concrete typically weighs about 4,000 pounds (approximately 2 tons) per cubic yard. This is important for calculating structural load and delivery truck capacity." },
  { q: "Should I add extra concrete to my order?", a: "Yes - always add 5-10% to your calculated volume to account for spills, uneven subgrade, and waste. For irregular shapes or critical projects, add 15%. Running short and doing a second pour creates a weak joint." },
  { q: "What is the standard thickness for a concrete driveway?", a: "Residential driveways typically use 4 inches thick for cars and 5-6 inches for trucks or heavy vehicles. Sidewalks are typically 4 inches, patios 3.5-4 inches, and structural slabs (for buildings) typically 4-6 inches." },
  { q: "Should I use ready-mix or bagged concrete?", a: "For projects under 1 cubic yard, bagged concrete is practical. Above 1 cubic yard, ready-mix is typically more cost-effective. Ready-mix is priced per cubic yard and delivered to your site - you avoid mixing labor and waste." },
  { q: "How long does concrete take to cure?", a: "Concrete reaches 70% strength in about 7 days and full strength (4,000 PSI) in 28 days. You can walk on it after 24-48 hours and drive on it after 7 days. Keep it moist (curing) for the first 3-7 days for maximum strength." },
];

export default function ConcreteCalculator() {
  const [shape, setShape] = useState("slab");
  const [lengthFt, setLengthFt] = useState(10);
  const [widthFt, setWidthFt] = useState(10);
  const [thicknessIn, setThicknessIn] = useState(4);
  const [diameterIn, setDiameterIn] = useState(12);
  const [heightFt, setHeightFt] = useState(4);
  const [waste, setWaste] = useState(10);

  let volumeCuFt = 0;
  if (shape === "slab") volumeCuFt = lengthFt * widthFt * (thicknessIn / 12);
  else if (shape === "column") volumeCuFt = Math.PI * Math.pow(diameterIn / 24, 2) * heightFt;
  else volumeCuFt = lengthFt * widthFt * (thicknessIn / 12) * 1.5;

  const withWaste = volumeCuFt * (1 + waste / 100);
  const cuYards = withWaste / 27;
  const bags80lb = Math.ceil(withWaste / 0.60);
  const bags60lb = Math.ceil(withWaste / 0.45);
  const costEstimate = cuYards * 130;

  return (
    <>
      <SEOHead
        title="Free Concrete Calculator Online - Calculate Cubic Yards Needed Instantly | CalcHive"
        description="Free online concrete calculator. Calculate cubic yards of concrete needed for slabs, columns and stairs instantly. 100% free for contractors and DIY builders, no signup required."
        canonical="/concrete-calculator"
        keywords="free concrete calculator, cubic yards concrete calculator free online, concrete slab calculator free, calculate concrete needed free, free construction concrete estimator"
        category="Construction Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-slate-600 dark:text-slate-400 bg-slate-100 dark:bg-slate-800/50 px-3 py-1 rounded-full mb-4 inline-block">Tools</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Concrete Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free concrete calculator to calculate concrete needed free for slabs, columns, and stairs. This cubic yards concrete calculator free online also works as a concrete slab calculator free and free construction concrete estimator.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="flex flex-wrap gap-2 mb-6">
            {SHAPES.map(s => (
              <button key={s.key} onClick={() => setShape(s.key)} className={`px-4 py-1.5 rounded-full text-sm font-semibold border transition-all ${shape === s.key ? "bg-primary text-primary-foreground border-primary" : "bg-muted text-muted-foreground border-border"}`}>{s.label}</button>
            ))}
          </div>
          <div className="space-y-6 mb-8">
            {shape === "slab" && (
              <>
                <SliderInput id="length-cc" label="Length" value={lengthFt} min={1} max={200} step={0.5} onChange={setLengthFt} format={v => `${v} ft`} testId="input-length" />
                <SliderInput id="width-cc" label="Width" value={widthFt} min={1} max={200} step={0.5} onChange={setWidthFt} format={v => `${v} ft`} testId="input-width" />
                <SliderInput id="thickness-cc" label="Thickness" value={thicknessIn} min={1} max={24} step={0.5} onChange={setThicknessIn} format={v => `${v} in`} testId="input-thickness" />
              </>
            )}
            {shape === "column" && (
              <>
                <SliderInput id="diameter-cc" label="Diameter" value={diameterIn} min={4} max={120} step={1} onChange={setDiameterIn} format={v => `${v} in`} testId="input-diameter" />
                <SliderInput id="height-cc" label="Height" value={heightFt} min={1} max={50} step={0.5} onChange={setHeightFt} format={v => `${v} ft`} testId="input-height" />
              </>
            )}
            {shape === "stairs" && (
              <>
                <SliderInput id="stair-length" label="Stair Width" value={lengthFt} min={1} max={20} step={0.5} onChange={setLengthFt} format={v => `${v} ft`} testId="input-length" />
                <SliderInput id="stair-run" label="Run Depth" value={widthFt} min={1} max={20} step={0.5} onChange={setWidthFt} format={v => `${v} ft`} testId="input-width" />
                <SliderInput id="stair-rise" label="Rise Height" value={thicknessIn} min={4} max={12} step={0.5} onChange={setThicknessIn} format={v => `${v} in`} testId="input-thickness" />
              </>
            )}
            <SliderInput id="waste-cc" label="Waste Factor" value={waste} min={0} max={25} step={1} onChange={setWaste} format={v => `${v}%`} testId="input-waste" />
          </div>
          <motion.div key={`${shape}-${lengthFt}-${widthFt}-${thicknessIn}-${diameterIn}-${heightFt}-${waste}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-slate-600 to-slate-800 rounded-2xl p-6 mb-4 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Concrete Needed</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-yards">{cuYards.toFixed(2)}</p>
              <p className="text-white/70 text-sm mt-1">cubic yards (incl. {waste}% waste)</p>
            </div>
            <div className="grid grid-cols-3 gap-3">
              {[{ label: "Cubic Feet", value: withWaste.toFixed(2) }, { label: "80-lb Bags", value: `${bags80lb} bags` }, { label: "60-lb Bags", value: `${bags60lb} bags` }].map(({ label, value }) => (
                <div key={label} className="bg-accent/60 border border-border rounded-xl p-4 text-center hover:shadow-sm transition-shadow">
                  <p className="text-xs text-muted-foreground font-medium mb-1">{label}</p>
                  <p className="text-lg font-extrabold text-foreground">{value}</p>
                </div>
              ))}
            </div>
            <p className="text-xs text-muted-foreground mt-3 text-center">Estimated cost: ~${costEstimate.toFixed(0)} (at $130/cu yd average for ready-mix)</p>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Cubic Yards of Concrete for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Concrete volume is measured in cubic yards (for ready-mix orders) or cubic feet (for bagged concrete). The formulas differ by shape.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-3">
            <div>
              <p className="text-xs text-muted-foreground uppercase tracking-widest mb-1">Slab or Footing</p>
              <p>Volume (cu ft) = Length (ft)  x  Width (ft)  x  Thickness (ft)</p>
              <p>Volume (cu yd) = Volume (cu ft)  x  27</p>
            </div>
            <div>
              <p className="text-xs text-muted-foreground uppercase tracking-widest mb-1">Column or Cylinder</p>
              <p>Volume (cu ft) = pi  x  (Diameter/2)-  x  Height (ft)</p>
            </div>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Concrete Needed for Slabs Columns and Stairs</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Project", "Standard Thickness", "Cubic Yards per 100 sq ft"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["Walkway / Sidewalk", "4 inches", "1.23 cu yd"],
                  ["Patio", "3.5-4 inches", "1.08-1.23 cu yd"],
                  ["Driveway (passenger cars)", "4 inches", "1.23 cu yd"],
                  ["Driveway (trucks)", "5-6 inches", "1.54-1.85 cu yd"],
                  ["Garage floor", "4-6 inches", "1.23-1.85 cu yd"],
                  ["Foundation slab", "4-8 inches", "1.23-2.47 cu yd"],
                  ["Swimming pool deck", "4 inches", "1.23 cu yd"],
                ].map(([project, thickness, volume]) => (
                  <tr key={project} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{project}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{thickness}</td>
                    <td className="py-2.5 px-4 text-slate-600 dark:text-slate-400 font-medium">{volume}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>

          <h2 className="text-2xl font-bold text-foreground">Free Concrete Estimator for Contractors and DIY Builders</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Option", "Best For", "Cost", "Convenience"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {[
                  ["Bagged concrete (80-lb)", "Under 0.5 cu yd", "$4-$6/bag (~$180+/cu yd)", "Easy, no truck needed, mix yourself"],
                  ["Bagged concrete (60-lb)", "Small repairs", "$3-$5/bag (~$200+/cu yd)", "Lighter, same mixing process"],
                  ["Ready-mix delivery", "0.5 cu yd and up", "$120-$160/cu yd + delivery", "No mixing, faster pour, minimum order"],
                ].map(([option, bestFor, cost, convenience]) => (
                  <tr key={option} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{option}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{bestFor}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{cost}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{convenience}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/concrete-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


